import java.util.*;

public class Graph<T> {
    private final Map<T, Set<T>> adj = new HashMap<>();

    public void addEdge(T from, T to) {
        adj.computeIfAbsent(from, k -> new HashSet<>()).add(to);
        adj.computeIfAbsent(to, k -> new HashSet<>()).add(from);
    }

    public Set<T> neighbors(T node) {
        return adj.getOrDefault(node, Collections.emptySet());
    }

    public boolean hasEdge(T from, T to) {
        return adj.getOrDefault(from, Collections.emptySet()).contains(to);
    }
}

import java.util.*;
import java.util.stream.Collectors;

public class WordCounter {
    public Map<String, Long> count(String text) {
        return Arrays.stream(text.toLowerCase().split("\\W+"))
            .filter(w -> !w.isBlank())
            .collect(Collectors.groupingBy(
                w -> w,
                Collectors.counting()
            ));
    }

    public List<Map.Entry<String, Long>> topN(String text, int n) {
        return count(text).entrySet().stream()
            .sorted(Map.Entry.<String, Long>comparingByValue().reversed())
            .limit(n)
            .collect(Collectors.toList());
    }
}
